input.content:
.overlay {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 5;
  pointer-events: none;
}

.card {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: var(--space-lg);
  padding: var(--space-xxl) 40px;
  background: var(--color-surface-glass);
  border: 1px solid var(--color-surface-glass-border);
  border-radius: var(--radius-lg);
  box-shadow: var(--shadow-glass);
  backdrop-filter: blur(12px);
  pointer-events: auto;
  max-width: 360px;
  text-align: center;
}

.title {
  font-family: var(--font-heading);
  font-size: 18px;
  font-weight: 700;
  color: var(--color-text-primary);
  margin: 0;
}

.subtitle {
  font-family: var(--font-ui);
  font-size: 13px;
  color: var(--color-text-secondary);
  line-height: 1.5;
  margin: 0;
}

.actions {
  display: flex;
  gap: var(--space-sm);
  margin-top: var(--space-sm);
}

.btnPrimary {
  padding: 8px 20px;
  border-radius: var(--radius-sm);
  border: none;
  background: var(--color-workspace-sketch, #B8860B);
  color: #fff;
  font-family: var(--font-ui);
  font-size: 13px;
  font-weight: 600;
  cursor: pointer;
  transition: background var(--duration-fast), transform var(--duration-micro);
}

.btnPrimary:hover {
  background: #9A7209;
}

.btnPrimary:active {
  transform: scale(0.97);
}

.btnSecondary {
  padding: 8px 20px;
  border-radius: var(--radius-sm);
  border: 1px solid var(--color-border);
  background: transparent;
  color: var(--color-text-primary);
  font-family: var(--font-ui);
  font-size: 13px;
  font-weight: 500;
  cursor: pointer;
  transition: background var(--duration-fast), border-color var(--duration-fast);
}

.btnSecondary:hover {
  background: rgba(0, 0, 0, 0.03);
  border-color: var(--color-workspace-sketch, #B8860B);
}

.btnSecondary:active {
  transform: scale(0.97);
}

