const handleSelectObject = (objectId) => {
  editorDispatch({
    type: 'SET_ACTIVE_OBJECT',
    objectId: activeObjectId === objectId ? null : objectId,
  });
};

const handleDeleteObject = (e, objectId) => {
  e.stopPropagation();
  dispatch({ type: 'OBJECT_DELETE', objectId });
  if (activeObjectId === objectId) {
    editorDispatch({ type: 'SET_ACTIVE_OBJECT', objectId: null });
  }
};

const handleDeleteLayer = (e, layerId) => {
  e.stopPropagation();
  if (project.layers.length <= 1) return;
  dispatch({ type: 'LAYER_DELETE', layerId });

  // If we're deleting the active layer, switch to the first remaining layer
  if (activeLayerId === layerId) {
    const remaining = project.layers.find((l) => l.id !== layerId);
    if (remaining) {
      editorDispatch({ type: 'SET_ACTIVE_LAYER', layerId: remaining.id });
    }
  }
};

